using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Plataforma que flutua na água (posição inicial = nível da superfície).
/// Soma o peso de quem está em cima (GameWeightUtil — mesma lógica da
/// WeightPlate/SeesawPlatform): enquanto o peso total não passar
/// "capacidadeMaxima", flutua normalmente (com balanço opcional). Acima
/// disso, afunda gradualmente — quem estiver em cima afunda com ela.
///
/// Pode combinar-se com MovingPlatform (ex: tronco que flutua E se desloca),
/// mas tem o seu próprio Rigidbody2D/posição vertical — não usar
/// "tipoMovimento = Vertical" ao mesmo tempo (conflito de eixo Y).
/// </summary>
[RequireComponent(typeof(Rigidbody2D))]
[DisallowMultipleComponent]
public class FloatingPlatform : MonoBehaviour
{
    [Header("Flutuação")]
    [Tooltip("Peso total suportado antes de começar a afundar (ver GameWeightUtil — peso da forma do player, ObjectWeight, etc).")]
    [Min(0.1f)] public float capacidadeMaxima = 2f;

    [Tooltip("Velocidade de afundamento por cada unidade de peso acima da capacidade.")]
    [Min(0f)] public float velocidadeAfundarPorPeso = 0.5f;

    [Tooltip("Profundidade máxima a partir da posição de flutuação (depois disso fica parada no fundo).")]
    [Min(0f)] public float profundidadeMaxima = 3f;

    [Tooltip("Velocidade com que volta a subir à superfície quando o peso é removido.")]
    [Min(0f)] public float velocidadeSubida = 1f;

    [Header("Balanço (opcional)")]
    [Tooltip("Amplitude do balanço suave vertical enquanto flutua sem peso extra (0 = sem balanço).")]
    [Min(0f)] public float amplitudeBalanco = 0.1f;

    [Min(0f)] public float velocidadeBalanco = 1f;

    [Header("Transporta o Player")]
    [Tooltip("Quem estiver em cima sobe/desce/balança junto com a plataforma.")]
    public bool transportaPlayer = true;

    [Header("Eventos")]
    public UnityEvent onComecouAAfundar;
    public UnityEvent onAfundouCompletamente;
    public UnityEvent onVoltouASuperficie;

    private Rigidbody2D _rb;
    private Collider2D _col;
    private Vector2 _floatPos;
    private float _currentDepth;
    private bool _isSinking;
    private bool _isFullySunk;
    private bool _isAtSurface = true;

    private readonly HashSet<Collider2D> _occupants = new HashSet<Collider2D>();

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
        _col = GetComponent<Collider2D>();
        _rb.bodyType = RigidbodyType2D.Kinematic;
        _floatPos = _rb.position;
    }

    private void FixedUpdate()
    {
        float totalWeight = 0f;
        foreach (var occ in _occupants)
        {
            if (occ == null) continue;
            totalWeight += GameWeightUtil.GetWeightOf(occ);
        }

        float excesso = Mathf.Max(0f, totalWeight - capacidadeMaxima);

        Vector2 oldPos = _rb.position;
        Vector2 newPos;

        bool sinkingNow = excesso > 0f;
        if (sinkingNow && !_isSinking) onComecouAAfundar?.Invoke();
        _isSinking = sinkingNow;

        if (sinkingNow)
        {
            _currentDepth = Mathf.Min(profundidadeMaxima, _currentDepth + velocidadeAfundarPorPeso * excesso * Time.fixedDeltaTime);
            newPos = _floatPos + Vector2.down * _currentDepth;
        }
        else
        {
            if (_currentDepth > 0f)
                _currentDepth = Mathf.Max(0f, _currentDepth - velocidadeSubida * Time.fixedDeltaTime);

            float bob = amplitudeBalanco > 0f ? Mathf.Sin(Time.time * velocidadeBalanco) * amplitudeBalanco : 0f;
            newPos = _floatPos + Vector2.down * _currentDepth + Vector2.up * bob;
        }

        bool fullySunkNow = profundidadeMaxima > 0f && _currentDepth >= profundidadeMaxima - 0.001f;
        if (fullySunkNow && !_isFullySunk) onAfundouCompletamente?.Invoke();
        _isFullySunk = fullySunkNow;

        bool atSurfaceNow = _currentDepth <= 0.001f;
        if (atSurfaceNow && !_isAtSurface) onVoltouASuperficie?.Invoke();
        _isAtSurface = atSurfaceNow;

        _rb.MovePosition(newPos);

        Vector2 delta = newPos - oldPos;
        if (transportaPlayer && delta.sqrMagnitude > 0f)
        {
            foreach (var occ in _occupants)
            {
                if (occ == null) continue;
                var occRb = occ.attachedRigidbody;
                if (occRb != null) occRb.position += delta;
            }
        }
    }

    private void OnCollisionEnter2D(Collision2D collision) => UpdateOccupant(collision, true);
    private void OnCollisionStay2D(Collision2D collision) => UpdateOccupant(collision, true);
    private void OnCollisionExit2D(Collision2D collision) => UpdateOccupant(collision, false);

    private void UpdateOccupant(Collision2D collision, bool entering)
    {
        if (!entering)
        {
            _occupants.Remove(collision.collider);
            return;
        }

        if (!IsOnTop(collision.collider)) return;
        _occupants.Add(collision.collider);
    }

    /// <summary>true se a base de "other" estiver acima do topo da plataforma (pisando-a, não a tocar de lado).</summary>
    private bool IsOnTop(Collider2D other)
    {
        if (_col == null) return true;
        return other.bounds.min.y >= _col.bounds.max.y - 0.15f;
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = Color.cyan;
        Vector2 pos = Application.isPlaying ? _floatPos : (Vector2)transform.position;
        Gizmos.DrawLine(pos + Vector2.left * 0.5f, pos + Vector2.right * 0.5f);

        if (profundidadeMaxima > 0f)
        {
            Gizmos.color = new Color(0f, 0.3f, 0.6f);
            Vector2 bottom = pos + Vector2.down * profundidadeMaxima;
            Gizmos.DrawLine(bottom + Vector2.left * 0.5f, bottom + Vector2.right * 0.5f);
            Gizmos.DrawLine(pos, bottom);
        }
    }
}
